// src/hooks/useFetch.js
import { useState, useEffect } from 'react';
import api from '../services/api';

/**
 * Simple data-fetching hook using our axios instance.
 * Usage: const { data, loading, error } = useFetch('/analytics');
 */
export const useFetch = (url, config = {}) => {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let cancelled = false;

    const fetchData = async () => {
      setLoading(true);
      setError(null);

      try {
        const res = await api.get(url, config);
        if (!cancelled) {
          // IMPORTANT: pass through exactly what backend sends
          setData(res.data);
        }
      } catch (err) {
        if (!cancelled) {
          console.error('useFetch error for', url, err);
          setError(err);
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    };

    fetchData();

    return () => {
      cancelled = true;
    };
  }, [url]);

  return { data, loading, error };
};

export default useFetch;

// src/pages/Admin/AdminDashboard.jsx
import React, { useState, useEffect } from 'react';
import { Users, Link2, Activity, Smartphone } from 'lucide-react';
import { Card } from '../../components/ui/Card';
import { StatsCard } from '../../components/analytics/StatsCard';
import { ClickChart } from '../../components/analytics/ClickChart';
import { useFetch } from '../../hooks/useFetch';
import { io } from 'socket.io-client';

const AdminDashboard = () => {
  const { data, loading, error } = useFetch('/admin/overview');
  const [liveData, setLiveData] = useState(null);

  // Sync initial fetch
  useEffect(() => {
    if (data) setLiveData(data);
  }, [data]);

  // Connect socket
  useEffect(() => {
    const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:5050';
    const socket = io(API_URL);

    socket.on('connect', () => {
      socket.emit('join-dashboard');
    });

    socket.on('link-click', (event) => {
      setLiveData((prev) => {
        if (!prev) return prev;

        const newEvent = {
          id: Math.random().toString(36).substr(2, 9),
          message: `🟢 LIVE: Click from ${event.country} on /${event.slug} via ${event.device} (${event.browser})`,
          createdAt: event.timestamp || new Date().toISOString()
        };

        return {
          ...prev,
          totalClicks: prev.totalClicks + 1,
          recentEvents: [newEvent, ...prev.recentEvents].slice(0, 50)
        };
      });
    });

    socket.on('traffic-anomaly', (event) => {
      setLiveData((prev) => {
        if (!prev) return prev;

        const newEvent = {
          id: Math.random().toString(36).substr(2, 9),
          message: `🚨 ALERT: Bot detected on /${event.slug} (Score: ${event.riskScore}) - ${event.reason}`,
          createdAt: event.timestamp || new Date().toISOString()
        };

        return {
          ...prev,
          recentEvents: [newEvent, ...prev.recentEvents].slice(0, 50)
        };
      });
    });

    return () => socket.disconnect();
  }, []);

  const displayData = liveData || data;

  const totalLinks = displayData?.totalLinks ?? 0;
  const totalClicks = displayData?.totalClicks ?? 0;
  const activeLinks = displayData?.activeLinks ?? 0;
  const uniqueVisitors = displayData?.uniqueVisitors ?? 0;
  const mobilePercent = displayData?.mobilePercent ?? 0;
  const botClicks = displayData?.botClicks ?? 0;
  const timeline = displayData?.timeline ?? [];
  const recentEvents = displayData?.recentEvents ?? [];

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 relative">
        <div>
          <h1 className="text-4xl font-bold text-white mb-2">Admin Dashboard</h1>
          <p className="text-lg text-slate-300">
            System overview and activity monitoring
          </p>
        </div>
        {!loading && displayData && (
          <div className="flex items-center gap-2 px-4 py-2 bg-emerald-500/20 border border-emerald-500/30 rounded-full">
            <div className="w-2.5 h-2.5 bg-emerald-400 rounded-full animate-pulse"></div>
            <span className="text-emerald-300 font-medium">Live Analytics Active</span>
          </div>
        )}
        <div className="absolute -top-4 -right-4 w-32 h-32 bg-purple-500/10 rounded-full blur-3xl"></div>
      </div>

      {error && (
        <div className="p-4 rounded-lg bg-red-500/10 border border-red-500/20 text-sm text-red-400">
          Failed to load admin overview: {error.message || 'Unknown error'}
        </div>
      )}

      {/* Top stats row */}
      <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-4">
        <StatsCard
          title="Total Clicks"
          value={loading ? '…' : totalClicks.toLocaleString()}
          icon={Activity}
        />
        <StatsCard
          title="Total Links"
          value={loading ? '…' : totalLinks.toLocaleString()}
          icon={Link2}
        />
        <StatsCard
          title="Active Links"
          value={loading ? '…' : activeLinks.toLocaleString()}
          icon={Users}
        />
        <StatsCard
          title="Mobile Share"
          value={loading ? '…' : `${mobilePercent}%`}
          icon={Smartphone}
        />
        <StatsCard
          title="Bot Clicks"
          value={loading ? '…' : botClicks.toLocaleString()}
          icon={Activity}
        />
      </div>

      {/* Charts + alerts row */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Traffic chart */}
        <div className="lg:col-span-2">
          <ClickChart data={timeline} loading={loading} />
        </div>

        {/* Recent system alerts */}
        <Card className="h-[400px] flex flex-col">
          <div className="mb-4">
            <h2 className="text-base font-semibold text-white mb-1">
              Live Activity Stream
            </h2>
            <p className="text-xs text-slate-500">
              Real-time platform events
            </p>
          </div>

          <div className="flex-1 overflow-y-auto space-y-2 pr-2">
            {loading && (
              <p className="text-sm text-slate-500">Loading...</p>
            )}

            {!loading && recentEvents.length === 0 && (
              <p className="text-sm text-slate-500">
                No recent activity
              </p>
            )}

            {!loading &&
              recentEvents.map((ev) => (
                <div
                  key={ev.id}
                  className="rounded-md bg-white/5 px-3 py-2 transition-all duration-300 animate-in fade-in slide-in-from-top-2"
                >
                  <p className="text-xs text-slate-200">{ev.message}</p>
                  <p className="text-[10px] text-slate-500 mt-1">
                    {new Date(ev.createdAt).toLocaleString()}
                  </p>
                </div>
              ))}
          </div>
        </Card>
      </div>
    </div>
  );
};

export default AdminDashboard;

import { useState, useEffect } from 'react';
import { Shield, Flag, CheckCircle, XCircle, Trash2, Ban, AlertTriangle } from 'lucide-react';
import { Card } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Badge } from '../../components/ui/Badge';
import { toast } from 'react-hot-toast';
import api from '../../services/api';

export default function Moderation() {
  const [reports, setReports] = useState([]);
  const [stats, setStats] = useState({});
  const [loading, setLoading] = useState(true);
  const [selectedReports, setSelectedReports] = useState([]);
  const [filters, setFilters] = useState({
    status: 'PENDING',
    priority: '',
    reason: ''
  });
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0 });
  const [reviewingId, setReviewingId] = useState(null);
  const [reviewNotes, setReviewNotes] = useState('');

  useEffect(() => {
    fetchReports();
    fetchStats();
  }, [filters, pagination.page]);

  const fetchStats = async () => {
    try {
      const response = await api.get('/moderation/stats');
      setStats(response.data);
    } catch (error) {
      console.error('Failed to fetch stats:', error);
    }
  };

  const fetchReports = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams({
        page: pagination.page,
        limit: 20,
        ...filters
      });

      const response = await api.get(`/moderation/reports?${params}`);
      setReports(response.data.reports);
      setPagination(response.data.pagination);
    } catch (error) {
      toast.error('Failed to load reports');
    } finally {
      setLoading(false);
    }
  };

  const handleReview = async (reportId, status, actionTaken) => {
    try {
      await api.patch(`/moderation/reports/${reportId}`, {
        status,
        actionTaken,
        reviewNotes
      });

      toast.success(`Report ${status.toLowerCase()}`, {
        style: { background: '#10b981', color: 'white' }
      });

      setReviewingId(null);
      setReviewNotes('');
      fetchReports();
      fetchStats();
    } catch (error) {
      toast.error('Failed to review report');
    }
  };

  const handleBulkAction = async (action) => {
    if (selectedReports.length === 0) {
      toast.error('No reports selected');
      return;
    }

    try {
      const response = await api.post('/moderation/reports/bulk', {
        reportIds: selectedReports,
        action,
        reviewNotes: `Bulk ${action.toLowerCase()}`
      });

      toast.success(response.data.message, {
        style: { background: '#10b981', color: 'white' }
      });

      setSelectedReports([]);
      fetchReports();
      fetchStats();
    } catch (error) {
      toast.error('Failed to perform bulk action');
    }
  };

  const toggleSelectReport = (reportId) => {
    setSelectedReports(prev => 
      prev.includes(reportId) 
        ? prev.filter(id => id !== reportId)
        : [...prev, reportId]
    );
  };

  const selectAll = () => {
    if (selectedReports.length === reports.length) {
      setSelectedReports([]);
    } else {
      setSelectedReports(reports.map(r => r._id));
    }
  };

  const getReasonColor = (reason) => {
    const colors = {
      SPAM: 'bg-yellow-500/20 text-yellow-400',
      MALWARE: 'bg-red-500/20 text-red-400',
      PHISHING: 'bg-red-500/20 text-red-400',
