                              )}
                            </div>

                            <p className="text-gray-300">{report.description}</p>

                            <div className="text-sm text-gray-400">
                              Reported by: {report.reporterEmail || 'Anonymous'} • {
                                new Date(report.createdAt).toLocaleString()
