                            )}
                          </div>
                        </div>

                        {/* Review Actions */}
                        {report.status === 'PENDING' && (
                          <div className="border-t border-gray-700 pt-3 space-y-3">
                            {reviewingId === report._id ? (
                              <>
                                <textarea
                                  value={reviewNotes}
                                  onChange={(e) => setReviewNotes(e.target.value)}
                                  placeholder="Add review notes (optional)..."
                                  className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:ring-2 focus:ring-purple-500"
                                  rows={2}
                                />
                                <div className="flex gap-2">
                                  <Button
                                    onClick={() => handleReview(report._id, 'APPROVED', 'NONE')}
                                    className="bg-green-600 hover:bg-green-700"
                                  >
                                    <CheckCircle className="w-4 h-4 mr-2" />
                                    Approve (No Action)
                                  </Button>
                                  <Button
                                    onClick={() => handleReview(report._id, 'APPROVED', 'BLOCKED')}
                                    className="bg-orange-600 hover:bg-orange-700"
                                  >
                                    <Ban className="w-4 h-4 mr-2" />
                                    Block Link
                                  </Button>
                                  <Button
                                    onClick={() => handleReview(report._id, 'APPROVED', 'DELETED')}
                                    className="bg-red-600 hover:bg-red-700"
                                  >
                                    <Trash2 className="w-4 h-4 mr-2" />
                                    Delete Link
                                  </Button>
                                  <Button
                                    onClick={() => handleReview(report._id, 'REJECTED', 'NONE')}
                                    variant="outline"
                                    className="border-gray-600"
                                  >
                                    <XCircle className="w-4 h-4 mr-2" />
                                    Reject
                                  </Button>
                                  <Button
                                    onClick={() => {
                                      setReviewingId(null);
                                      setReviewNotes('');
                                    }}
                                    variant="outline"
                                    className="border-gray-600"
                                  >
                                    Cancel
                                  </Button>
                                </div>
                              </>
                            ) : (
                              <Button
                                onClick={() => setReviewingId(report._id)}
                                className="bg-purple-600 hover:bg-purple-700"
                              >
                                Review Report
                              </Button>
                            )}
                          </div>
                        )}
                      </div>
                    </div>
                  </Card>
                ))}
              </div>
            )}

            {/* Pagination */}
            {pagination.pages > 1 && (
              <div className="flex justify-center gap-2 mt-6">
                <Button
                  onClick={() => setPagination({ ...pagination, page: pagination.page - 1 })}
                  disabled={pagination.page === 1}
                  variant="outline"
                  className="border-gray-600"
                >
                  Previous
                </Button>
                <span className="text-gray-400 px-4 py-2">
                  Page {pagination.page} of {pagination.pages}
                </span>
                <Button
                  onClick={() => setPagination({ ...pagination, page: pagination.page + 1 })}
                  disabled={pagination.page === pagination.pages}
                  variant="outline"
                  className="border-gray-600"
                >
                  Next
                </Button>
              </div>
            )}
          </div>
        </Card>
      </div>
    </div>
  );
}

import React, { useEffect, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { Loader } from '../../components/ui/Loader';
import toast from 'react-hot-toast';
import api from '../../services/api';

const OAuthCallback = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { login } = useAuth();
  const hasRun = useRef(false);

  useEffect(() => {
    // Prevent duplicate execution in React StrictMode
    if (hasRun.current) return;
    hasRun.current = true;
    const handleOAuth = async () => {
      const token = searchParams.get('token');
      const error = searchParams.get('error');

      if (error) {
        toast.error('OAuth login failed');
        navigate('/login', { replace: true });
        return;
      }

      if (!token) {
        toast.error('No token received');
        navigate('/login', { replace: true });
        return;
      }

      try {
        // Fetch user details
        const response = await api.get('/auth/me', {
          headers: { Authorization: `Bearer ${token}` }
        });

        const user = response.data.user;
        if (!user) throw new Error('No user data');

        // Login
        login(user, token);

        // Redirect
        const destination = user.role === 'admin' ? '/admin' : '/dashboard';
        toast.success(`Welcome, ${user.name}!`);
        navigate(destination, { replace: true });
      } catch (err) {
        console.error('OAuth error:', err);
        toast.error('Authentication failed');
        navigate('/login', { replace: true });
      }
    };

    handleOAuth();
  }, []); // Empty dependency - run once

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-950">
      <Loader />
    </div>
  );
};

export default OAuthCallback;

