import React, { useState, useEffect } from 'react';
import { toast } from 'react-hot-toast';
import api from '../../services/api';

const DeveloperPortal = () => {
  const [keys, setKeys] = useState([]);
  const [name, setName] = useState('');
  const [newKeyData, setNewKeyData] = useState(null);

  useEffect(() => {
    fetchKeys();
  }, []);

  const fetchKeys = async () => {
    try {
      const res = await api.get('/keys');
      setKeys(res.data);
    } catch (err) {
      toast.error('Failed to fetch API keys');
    }
  };

  const handleGenerate = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/keys', { name });

      setNewKeyData(res.data);
      setName('');
      fetchKeys();
      toast.success('API Key generated successfully');
    } catch (err) {
      toast.error('Server error');
    }
  };

  const handleRevoke = async (id) => {
    try {
      await api.delete(`/keys/${id}`);
      toast.success('API Key revoked');
      fetchKeys();
    } catch (err) {
      toast.error('Failed to revoke key');
    }
  };

  const copyToClipboard = (text) => {
    navigator.clipboard.writeText(text);
    toast.success('Copied to clipboard');
  };

  return (
    <div className="p-6">
      <h1 className="text-3xl font-bold text-white mb-2">Developer Portal</h1>
      <p className="text-slate-400 mb-8">Manage your API keys for programmatic access to VanishLink.</p>

      {newKeyData && (
        <div className="bg-green-900/30 border border-green-500/50 p-6 rounded-lg mb-8">
          <h2 className="text-xl font-semibold text-green-400 mb-2">Save Your New API Key</h2>
          <p className="text-green-200/70 mb-4 text-sm">
            Please copy this key and store it securely. For security reasons, it will never be shown again!
          </p>
          <div className="flex gap-2">
            <input 
              type="text" 
              readOnly 
              value={newKeyData.key} 
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white font-mono"
            />
            <button 
              onClick={() => copyToClipboard(newKeyData.key)}
              className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg font-medium transition-colors"
            >
              Copy
            </button>
          </div>
          <button 
            onClick={() => setNewKeyData(null)}
            className="mt-4 text-sm text-slate-400 hover:text-white"
          >
            I have saved it, close this message.
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1">
          <div className="bg-slate-800 rounded-xl p-6 border border-slate-700">
            <h2 className="text-xl font-semibold text-white mb-4">Generate New Key</h2>
            <form onSubmit={handleGenerate}>
              <div className="mb-4">
                <label className="block text-sm font-medium text-slate-300 mb-1">Key Name / Identifier</label>
                <input
                  type="text"
                  required
                  placeholder="e.g. Production Environment"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:outline-none focus:border-indigo-500"
                />
              </div>
              <button 
                type="submit"
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-medium py-2 rounded-lg transition-colors"
              >
                Generate API Key
              </button>
            </form>
          </div>
        </div>

        <div className="lg:col-span-2">
          <div className="bg-slate-800 rounded-xl border border-slate-700 overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-900 border-b border-slate-700">
                <tr>
                  <th className="px-6 py-4 text-sm font-medium text-slate-400">Name</th>
                  <th className="px-6 py-4 text-sm font-medium text-slate-400">Created</th>
                  <th className="px-6 py-4 text-sm font-medium text-slate-400">Last Used</th>
                  <th className="px-6 py-4 text-sm font-medium text-slate-400 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-700">
                {keys.length === 0 ? (
                  <tr>
                    <td colSpan="4" className="px-6 py-8 text-center text-slate-400">
                      No API keys generated yet.
                    </td>
                  </tr>
                ) : (
                  keys.map(key => (
                    <tr key={key._id} className="hover:bg-slate-800/50">
                      <td className="px-6 py-4">
                        <div className="text-white font-medium">{key.name}</div>
                        <div className="text-xs text-slate-400 mt-1">{key.scopes.join(', ')}</div>
                      </td>
                      <td className="px-6 py-4 text-sm text-slate-300">
                        {new Date(key.createdAt).toLocaleDateString()}
                      </td>
                      <td className="px-6 py-4 text-sm text-slate-300">
                        {key.lastUsedAt ? new Date(key.lastUsedAt).toLocaleDateString() : 'Never'}
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => handleRevoke(key._id)}
                          className="text-red-400 hover:text-red-300 text-sm font-medium transition-colors"
                        >
                          Revoke
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DeveloperPortal;

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { Button } from '../../components/ui/Button';
import { CreateLinkForm } from '../../components/links/CreateLinkForm';
import { APP_BASE_URL } from '../../config/appUrl'; // 🔥 use app base url
import api from '../../services/api';
import { Zap, Link as LinkIcon, Gauge, CheckCircle } from 'lucide-react';

const DashboardHome = () => {
  const navigate = useNavigate();

  // store last created short URL for display + copy
  const [shortUrl, setShortUrl] = useState('');

  // basic stats for overview cards
  const [stats, setStats] = useState({
    total: 0,
    active: 0,
    clicks: 0,
    loading: true,
  });

  const handleLinkCreated = (link) => {
    // link comes from CreateLinkForm onSuccess
    const generatedShort = `${APP_BASE_URL}/${link.slug}`; // 🔥 not localhost
    setShortUrl(generatedShort);
  };

  const handleCopyShortUrl = async () => {
    if (!shortUrl) return;
    try {
      await navigator.clipboard.writeText(shortUrl);
      toast.success('Short link copied to clipboard!');
    } catch (err) {
      toast.error('Failed to copy. You can copy it manually.');
    }
  };

  // load link stats for overview
  useEffect(() => {
    const loadStats = async () => {
      try {
        setStats((s) => ({ ...s, loading: true }));
        const res = await api.get('/links');
        const links = Array.isArray(res.data) ? res.data : [];

        const total = links.length;
        const active = links.filter((l) => l.status !== 'expired').length;
        const clicks = links.reduce((sum, l) => sum + (l.clicks || 0), 0);

        setStats({ total, active, clicks, loading: false });
      } catch (err) {
        console.error('Failed to load stats', err);
        setStats({ total: 0, active: 0, clicks: 0, loading: false });
      }
    };

    loadStats();
  }, []);

  return (
    <div className="h-full w-full space-y-8">
      <div className="relative">
        <h1 className="text-4xl font-bold text-white mb-2">Dashboard</h1>
        <p className="text-lg text-slate-300">Create and manage your vanish links</p>
        <div className="absolute -top-4 -right-4 w-32 h-32 bg-emerald-500/10 rounded-full blur-3xl"></div>
      </div>

      {/* Link Creator */}
      <div className="bg-linear-to-br from-slate-800/90 to-slate-900/90 backdrop-blur-xl border border-slate-700/50 p-8 rounded-2xl shadow-2xl shadow-black/20">
        <div className="flex items-center gap-3 mb-6">
          <div className="w-10 h-10 rounded-lg bg-linear-to-br from-emerald-500/20 to-emerald-600/10 border border-emerald-500/30 flex items-center justify-center">
            <Zap className="w-5 h-5 text-emerald-400" />
          </div>
          <h2 className="text-xl font-bold text-white">
            Create New Link
          </h2>
        </div>

        {/* Single source of truth for link creation */}
        <CreateLinkForm onSuccess={handleLinkCreated} />

        {/* Show result only when we have a short URL */}
        {shortUrl && (
          <div className="mt-6 border border-emerald-500/30 rounded-xl p-5 bg-linear-to-br from-emerald-500/10 to-emerald-600/5 shadow-lg">
            <p className="text-emerald-400 font-semibold mb-3 flex items-center gap-2">
              <CheckCircle className="w-5 h-5" />
              Link created successfully
            </p>
            <div className="flex flex-col md:flex-row gap-3 md:items-center">
              <span className="break-all text-sm bg-slate-800/80 px-4 py-3 rounded-lg border border-slate-600/50 text-slate-100 font-mono flex-1">
                {shortUrl}
              </span>
              <Button
                type="button"
                onClick={handleCopyShortUrl}
                className="md:w-auto w-full"
              >
                Copy Link
              </Button>
            </div>
          </div>
        )}
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {[
          { label: 'Total Links', value: stats.loading ? '…' : stats.total, icon: LinkIcon },
          { label: 'Active Links', value: stats.loading ? '…' : stats.active, icon: Zap },
          { label: 'Total Clicks', value: stats.loading ? '…' : stats.clicks.toLocaleString(), icon: Gauge },
        ].map((item) => {
          const Icon = item.icon;

          return (
            <div
              key={item.label}
              className="bg-white/5 border border-slate-200/10 p-6 rounded-lg shadow-sm"
            >
              <div className="flex items-center justify-between mb-3">
                <span className="text-sm font-medium text-slate-400">
                  {item.label}
                </span>
                <Icon className="w-5 h-5 text-slate-500" />
              </div>
              <p className="text-3xl font-semibold text-white">{item.value}</p>
            </div>
          );
        })}
      </div>

      {/* Empty State Action */}
      {stats.loading || stats.total === 0 ? (
        <div className="bg-white/5 border border-slate-200/10 p-12 rounded-lg text-center">
          <div className="w-16 h-16 rounded-lg bg-white/5 flex items-center justify-center mx-auto mb-4">
            <LinkIcon className="w-8 h-8 text-slate-500" />
          </div>
          <h3 className="text-white text-lg font-semibold mb-2">
            {stats.loading ? 'Loading links...' : 'No links created yet'}
          </h3>
          <p className="text-slate-400 text-sm mb-6">
            {stats.loading
              ? 'Fetching your link activity.'
              : 'Create your first vanish link to start tracking and monitoring.'}
          </p>
          <Button onClick={() => navigate('/dashboard/links')}>
            Create First Link
          </Button>
        </div>
      ) : null}
    </div>
  );
};

export default DashboardHome;

import React, { useState, useEffect } from 'react';
import {
  Plus,
  ExternalLink,
  Copy,
  QrCode,
  Lock,
  Flame,
  Eye,
  FolderOpen,
  Star,
  Filter,
  Search,
  ShieldCheck,
  ShieldAlert,
} from 'lucide-react';
import { Button } from '../../components/ui/Button';
import { Modal } from '../../components/ui/Modal';
import { CreateLinkForm } from '../../components/links/CreateLinkForm';
import { EditLinkForm } from '../../components/links/EditLinkForm';
import { LinkActionMenu } from '../../components/links/LinkActionMenu';
import { DeleteConfirmationModal } from '../../components/links/DeleteConfirmationModal';
import { Table } from '../../components/ui/Table';
import { Badge } from '../../components/ui/Badge';
import { useClipboard } from '../../hooks/useClipboard';
import { QRPopup } from '../../components/links/QRPopup';
import { ReportLinkButton } from '../../components/links/ReportLinkButton';
import api from '../../services/api';
import { APP_BASE_URL } from '../../config/appUrl'; // uses env + origin
import { useAuth } from '../../hooks/useAuth';

const StatusBadges = ({ link }) => {
  const badges = [];
  const now = new Date();

  const isExpired =
    link.status === 'expired' ||
    (link.expiresAt && new Date(link.expiresAt) < now);

  if (isExpired) {
    badges.push(
      <span
        key="expired"
        className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-red-500/10 text-red-300 border border-red-500/40"
      >
        Expired
      </span>,
    );
  }

  if (link.scheduleStart && new Date(link.scheduleStart) > now) {
    badges.push(
      <span
        key="scheduled"
        className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-amber-500/10 text-amber-300 border border-amber-500/40"
      >
        Scheduled
      </span>,
    );
  }

  if (link.isOneTime || (link.maxClicks && link.maxClicks > 0)) {
    badges.push(
      <span
        key="burn"
        className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-orange-500/10 text-orange-300 border border-orange-500/40"
      >
        Burn-on-open
      </span>,
    );
  }

  if (link.password) {
    badges.push(
      <span
        key="locked"
        className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-slate-500/10 text-slate-200 border border-slate-500/40"
      >
        Locked
      </span>,
    );
  }

  if (link.showPreview) {
    badges.push(
      <span
        key="preview"
        className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-emerald-500/10 text-emerald-300 border border-emerald-500/40"
      >
        Preview
      </span>,
    );
  }

  if (link.scanStatus) {
    if (link.scanStatus === 'safe') {
      badges.push(
        <span
          key="scan-safe"
          className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-emerald-500/10 text-emerald-300 border border-emerald-500/40"
        >
          Safe Link
        </span>,
      );
    } else if (link.scanStatus === 'suspicious') {
      badges.push(
        <span
          key="scan-suspicious"
          className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-amber-500/10 text-amber-300 border border-amber-500/40 animate-pulse"
        >
          Suspicious ({link.riskScore || 0}%)
        </span>,
      );
    } else if (link.scanStatus === 'dangerous') {
      badges.push(
        <span
          key="scan-dangerous"
          className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-red-500/10 text-red-300 border border-red-500/40"
        >
          Dangerous! ({link.riskScore || 0}%)
        </span>,
      );
    } else if (link.scanStatus === 'pending') {
      badges.push(
        <span
          key="scan-pending"
          className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-slate-500/10 text-slate-300 border border-slate-500/40 animate-pulse"
        >
          Scanning...
        </span>,
      );
    }
  }

  if (link.routingMode && link.routingMode !== 'single') {
    badges.push(
      <span
        key="routing-mode"
        className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-medium bg-purple-500/10 text-purple-300 border border-purple-500/40"
      >
        A/B: {link.routingMode}
      </span>,
    );
  }

  if (badges.length === 0) return null;

  return <div className="flex flex-wrap gap-1 mt-1">{badges}</div>;
};

const getLinkAvatar = (link) => {
  const seed = encodeURIComponent(
    link.title || link.slug || link.targetUrl || 'Vanish Agent',
  );
  return `https://api.dicebear.com/7.x/bottts/svg?seed=${seed}`;
};

// Build the public URL for a slug safely
const buildLinkUrl = (slug) => {
  const base = APP_BASE_URL || window.location.origin;
  const cleanBase = base.replace(/\/+$/, '');
  return `${cleanBase}/${slug}`;
};

const MyLinks = () => {
  const { user } = useAuth();
  const [isCreateOpen, setCreateOpen] = useState(false);
  const [editingLink, setEditingLink] = useState(null);
  const [deleteLink, setDeleteLink] = useState(null);
  const [qrLink, setQrLink] = useState(null);
  const [filter, setFilter] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');

  const [links, setLinks] = useState([]);
  const [loading, setLoading] = useState(true);

  const { copy } = useClipboard();

  // Fetch user's links only (backend filters by authenticated user)
  const loadLinks = async () => {
    try {
      setLoading(true);
      const res = await api.get('/links');
      setLinks(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      console.error('Failed to load links', err);
      setLinks([]);
    } finally {
      setLoading(false);
    }
  };

  const handleToggleFavorite = async (link) => {
    try {
      const res = await api.patch(`/links/${link._id}/favorite`);
      setLinks((prev) =>
        prev.map((l) => (l._id === link._id ? res.data : l))
      );
    } catch (err) {
      console.error('Failed to toggle favorite', err);
    }
  };

  useEffect(() => {
    loadLinks();
  }, []);

  const handleLinkCreated = () => {
    setCreateOpen(false);
    loadLinks();
  };

  const handleEditLink = (link) => {
    setEditingLink(link);
  };

  const handleEditSuccess = (updatedLink) => {
    // Update the link in the list
    setLinks((prev) =>
      prev.map((l) => (l._id === updatedLink._id ? updatedLink : l))
    );
    setEditingLink(null);
  };

  const handleDeleteLink = (link) => {
    setDeleteLink(link);
  };

  const handleDeletedLink = (linkId) => {
    setLinks((prev) => prev.filter((l) => l._id !== linkId));
    setDeleteLink(null);
  };

  // Apply collection filter and search
  const filteredLinks = Array.isArray(links)
    ? links.filter((link) => {
        // Collection filter
        if (filter !== 'All') {
          const collection =
            link.collectionName || link.collection || 'General';
          if (collection !== filter) return false;
        }

        // Search filter
        if (searchTerm) {
          const search = searchTerm.toLowerCase();
          return (
            link.title?.toLowerCase().includes(search) ||
            link.slug?.toLowerCase().includes(search) ||
            link.targetUrl?.toLowerCase().includes(search)
          );
        }

        return true;
      })
    : [];

  // Calculate collection counts
  const collectionCounts = {
    All: links.length,
    General: links.filter((l) => (l.collection || 'General') === 'General')
      .length,
    Intel: links.filter((l) => (l.collection || 'General') === 'Intel')
      .length,
    Personal: links.filter((l) => (l.collection || 'General') === 'Personal')
      .length,
  };

  const columns = [
    {
      header: 'Identity',
      className: 'w-1/3',
      cell: (row) => (
        <div className="flex items-center gap-3">
          {/* Favorite button */}
          <button
            onClick={() => handleToggleFavorite(row)}
            className={`transition-colors ${
              row.isFavorite
                ? 'text-yellow-400'
                : 'text-slate-600 hover:text-yellow-400'
            }`}
            title={row.isFavorite ? 'Remove from favorites' : 'Mark as favorite'}
          >
            <Star
              className="w-4 h-4"
              fill={row.isFavorite ? 'currentColor' : 'none'}
            />
          </button>

          {/* Link avatar */}
          <img
            src={getLinkAvatar(row)}
            alt={row.title || 'Link avatar'}
            className="w-9 h-9 rounded-full border border-slate-700 bg-slate-800 object-cover shrink-0"
          />

          {/* Icon + title + url + badges + creator */}
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2">
              <div className="w-9 h-9 rounded-lg bg-slate-800 flex items-center justify-center text-slate-400 shrink-0 border border-slate-700">
                {row.status === 'expired' ? (
                  <Flame className="w-5 h-5 text-red-500" />
                ) : (
                  <ExternalLink className="w-5 h-5" />
                )}
              </div>
              <div className="min-w-0 flex-1">
                <div className="font-medium text-slate-200 truncate">
                  {row.title || 'Untitled Operation'}
                </div>
                <div className="text-xs text-slate-500 truncate max-w-[200px]">
                  {row.targetUrl}
                </div>
                {row.creatorName && (
                  <div className="text-xs text-slate-400 mt-0.5">
                    by {row.creatorName}
                  </div>
                )}
              </div>
            </div>
            <StatusBadges link={row} />
          </div>
        </div>
      ),
    },
    {
      header: 'Security',
      cell: (row) => (
        <div className="flex gap-2">
          {row.password && (
            <Lock
              className="w-4 h-4 text-emerald-500"
              title="Password Protected"
            />
          )}
          {(row.isOneTime || (row.maxClicks && row.maxClicks > 0)) && (
            <Flame
              className="w-4 h-4 text-orange-500"
              title="Self-Destruct / Limited Clicks"
            />
          )}
          {row.showPreview && (
            <Eye
              className="w-4 h-4 text-blue-500"
              title="Safe Preview Enabled"
            />
          )}
          {row.scanStatus === 'safe' && (
            <ShieldCheck
              className="w-4 h-4 text-emerald-400"
              title={`Url Scan: Safe (Risk: ${row.riskScore || 0}%)`}
            />
          )}
          {row.scanStatus === 'suspicious' && (
            <ShieldAlert
              className="w-4 h-4 text-amber-400 animate-pulse"
              title={`Url Scan: Suspicious (Risk: ${row.riskScore || 0}%)`}
            />
          )}
          {row.scanStatus === 'dangerous' && (
            <ShieldAlert
              className="w-4 h-4 text-red-500 animate-bounce"
              title={`Url Scan: Dangerous! (Risk: ${row.riskScore || 0}%)`}
            />
          )}
          {row.scanStatus === 'pending' && (
            <ShieldAlert
              className="w-4 h-4 text-slate-500 animate-pulse"
              title="Url Scan: Scanning..."
            />
          )}
        </div>
      ),
    },
    {
      header: 'Short Link',
      cell: (row) => {
        const url = buildLinkUrl(row.slug);

        return (
          <div className="flex items-center gap-2 bg-slate-950/50 p-1.5 rounded-lg border border-slate-800 w-fit">
            <span className="font-mono text-[11px] text-emerald-400 pl-1">
              /{row.slug}
            </span>
            <div className="h-4 w-px bg-slate-800 mx-1" />
            <button
              onClick={(e) => {
                e.stopPropagation();
                copy(url);
              }}
              className="hover:text-white text-slate-500"
              title="Copy Link"
            >
              <Copy className="w-3.5 h-3.5" />
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation();
                setQrLink(url);
              }}
              className="hover:text-white text-slate-500"
              title="Get QR Code"
            >
              <QrCode className="w-3.5 h-3.5" />
            </button>
          </div>
        );
      },
    },
    {
      header: 'Status',
      cell: (row) => {
        const now = new Date();
        const isExpired =
          row.status === 'expired' ||
          (row.expiresAt && new Date(row.expiresAt) < now);
        const isScheduled =
          row.scheduleStart && new Date(row.scheduleStart) > now;

        let label = 'Active';
        if (isExpired) label = 'Expired';
        else if (isScheduled) label = 'Scheduled';

        return <Badge variant={isExpired ? 'danger' : 'success'}>{label}</Badge>;
      },
    },
    {
      header: 'Clicks',
      accessor: 'clicks',
      className: 'text-center font-mono text-slate-400',
    },
    {
      header: 'Created',
      cell: (row) => (
        <span className="text-slate-500 text-xs">
          {row.createdAt
            ? new Date(row.createdAt).toLocaleDateString()
            : '--'}
        </span>
      ),
    },
    {
      header: 'Actions',
      cell: (row) => {
        const url = buildLinkUrl(row.slug);
        return (
          <div className="flex items-center gap-2">
            <LinkActionMenu
              link={row}
              url={url}
              onEdit={() => handleEditLink(row)}
              onDelete={() => handleDeleteLink(row)}
            />
            <ReportLinkButton 
              linkId={row._id} 
              linkSlug={row.slug}
            />
          </div>
        );
      },
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-semibold text-white mb-1">My Links</h1>
          <p className="text-sm text-slate-400">
            Manage and track your secure endpoints
          </p>
        </div>
        <div className="flex gap-3 flex-col sm:flex-row">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
            <input
              type="text"
              placeholder="Search links..."
              className="bg-white/5 border border-slate-200/10 text-slate-200 text-sm rounded-md pl-9 pr-4 py-2 focus:outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 w-full sm:w-64"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="relative">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
            <select
              className="bg-white/5 border border-slate-200/10 text-slate-200 text-sm rounded-md pl-9 pr-4 py-2 focus:outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 appearance-none"
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
            >
              <option value="All">
                All Collections ({collectionCounts.All})
              </option>
              <option value="General">
                General ({collectionCounts.General})
              </option>
              <option value="Intel">
                Intel ({collectionCounts.Intel})
              </option>
              <option value="Personal">
                Personal ({collectionCounts.Personal})
              </option>
            </select>
          </div>
          <Button
            onClick={() => setCreateOpen(true)}
            className="w-full sm:w-auto px-6"
          >
            <Plus className="w-4 h-4 mr-2" />
            Create Link
          </Button>
        </div>
      </div>

      <Table columns={columns} data={filteredLinks} isLoading={loading} />

      <Modal
        isOpen={isCreateOpen}
        onClose={() => setCreateOpen(false)}
        title="Create Secure Link"
      >
        <CreateLinkForm onSuccess={handleLinkCreated} />
      </Modal>

      <Modal
        isOpen={!!editingLink}
        onClose={() => setEditingLink(null)}
        title="Edit Link"
      >
        {editingLink && (
          <EditLinkForm
            link={editingLink}
            onSuccess={handleEditSuccess}
          />
        )}
      </Modal>

      <DeleteConfirmationModal
        isOpen={!!deleteLink}
        onClose={() => setDeleteLink(null)}
        link={deleteLink}
        onDeleted={handleDeletedLink}
      />

      <QRPopup
        isOpen={!!qrLink}
        onClose={() => setQrLink(null)}
        url={qrLink || ''}
      />
    </div>
  );
};

export default MyLinks;

// src/pages/Dashboard/Settings.jsx
import React, { useEffect, useState } from 'react';
import { Card } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { useAuth } from '../../context/AuthContext';
import {
  User,
  Lock,
  Bell,
  Globe,
  Shield,
  AlertTriangle,
  Trash2,
  Download,
} from 'lucide-react';
import api from '../../services/api';
import toast from 'react-hot-toast';

const colorOptions = ['#10B981', '#6366F1', '#F59E0B', '#EF4444', '#EC4899'];

const Settings = () => {
  const { user, login } = useAuth();

  // ---- profile/basic ----
  const [displayName, setDisplayName] = useState(user?.name || '');
  const [avatarColor, setAvatarColor] = useState('#10B981');
  const [timezone, setTimezone] = useState('UTC');
  const [loadingProfile, setLoadingProfile] = useState(false);

  // ---- password ----
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [loadingPassword, setLoadingPassword] = useState(false);

  // ---- notifications ----
  const [emailOnDestruction, setEmailOnDestruction] = useState(true);
  const [suspiciousActivity, setSuspiciousActivity] = useState(true);
  const [loadingNotifications, setLoadingNotifications] = useState(false);

  // ---- default link settings ----
  const [defaultCollection, setDefaultCollection] = useState('General');
  const [defaultShowPreview, setDefaultShowPreview] = useState(true);
  const [defaultMaxClicks, setDefaultMaxClicks] = useState(0);
  const [defaultIsOneTime, setDefaultIsOneTime] = useState(false);

  // ---- privacy ----
  const [showCreatorName, setShowCreatorName] = useState(true);
  const [enableReferrerTracking, setEnableReferrerTracking] =
    useState(true);
  const [allowLinkSuggestions, setAllowLinkSuggestions] = useState(true); // NEW

  // ---- auto-destruct ----
  const [autoExpireDays, setAutoExpireDays] = useState('');
  const [autoDestroyOnFirstClick, setAutoDestroyOnFirstClick] =
    useState(false);

  // ---- advanced security ----
  const [notifyNewDevice, setNotifyNewDevice] = useState(true);
  const [notifyFailedAttempt, setNotifyFailedAttempt] = useState(true);
  const [twoFactorEnabled, setTwoFactorEnabled] = useState(false);
  const [loadingSecurity, setLoadingSecurity] = useState(false);

  // ---- danger zone actions ----
  const [loadingExport, setLoadingExport] = useState(false);
  const [loadingResetData, setLoadingResetData] = useState(false);
  const [loadingDeleteAccount, setLoadingDeleteAccount] = useState(false);

  const [sessions, setSessions] = useState([]);

  // Fetch settings from backend on mount
  useEffect(() => {
    const fetchSettings = async () => {
      if (!user?.email) return;

      try {
        const res = await api.get('/settings', {
          params: { email: user.email },
        });

        setDisplayName(res.data.name || user.name || '');
        setAvatarColor(res.data.avatarColor || '#10B981');
        setTimezone(res.data.timezone || 'UTC');

        setEmailOnDestruction(
          res.data.notifications?.emailOnDestruction ?? true
        );
        setSuspiciousActivity(
          res.data.notifications?.suspiciousActivity ?? true
        );

        const def = res.data.defaultSettings || {};
        setDefaultCollection(def.collection || 'General');
        setDefaultShowPreview(
          def.showPreview !== undefined ? def.showPreview : true
        );
        setDefaultMaxClicks(def.maxClicks ?? 0);
        setDefaultIsOneTime(def.isOneTime ?? false);

        const priv = res.data.privacy || {};
        setShowCreatorName(
          priv.showCreatorName !== undefined ? priv.showCreatorName : true
        );
        setEnableReferrerTracking(
          priv.enableReferrerTracking !== undefined
            ? priv.enableReferrerTracking
            : true
        );
        setAllowLinkSuggestions(
          priv.allowLinkSuggestions !== undefined
            ? priv.allowLinkSuggestions
            : true
        );

        const auto = res.data.autoDestructRules || {};
        setAutoExpireDays(
          auto.expireAfterDays !== null &&
          auto.expireAfterDays !== undefined
            ? String(auto.expireAfterDays)
            : ''
        );
        setAutoDestroyOnFirstClick(auto.destroyOnFirstClick ?? false);

        const sec = res.data.securitySettings || {};
        setNotifyNewDevice(
          sec.notifyNewDevice !== undefined ? sec.notifyNewDevice : true
        );
        setNotifyFailedAttempt(
          sec.notifyFailedAttempt !== undefined
            ? sec.notifyFailedAttempt
            : true
        );

        setTwoFactorEnabled(res.data.twoFactorEnabled ?? false);
        setSessions(res.data.sessions || []);
      } catch (err) {
        console.error('Failed to load settings', err);
        toast.error('Failed to load settings');
      }
    };

    fetchSettings();
  }, [user?.email]);

  // ---- handlers ----

  const handleUpdateProfile = async () => {
    if (!user?.email) return;

    try {
      setLoadingProfile(true);
      const res = await api.put('/settings/profile', {
        email: user.email,
        name: displayName,
        avatarColor,
        timezone,
      });

      login({
        ...user,
        name: res.data.user.name,
      });

      toast.success('Profile updated');
    } catch (err) {
      console.error('Failed to update profile', err);
      toast.error('Failed to update profile');
    } finally {
      setLoadingProfile(false);
    }
  };

  const handleChangePassword = async () => {
    if (!user?.email) return;

    if (!newPassword || newPassword.length < 6) {
      toast.error('New password should be at least 6 characters');
      return;
    }

    try {
      setLoadingPassword(true);
      await api.put('/settings/password', {
        email: user.email,
        currentPassword,
        newPassword,
      });

      toast.success('Password updated');
      setCurrentPassword('');
      setNewPassword('');
    } catch (err) {
      console.error('Failed to change password', err);
      const msg =
        err?.response?.data?.message || 'Failed to change password';
      toast.error(msg);
    } finally {
      setLoadingPassword(false);
    }
  };

  const saveNotifications = async (nextState) => {
    if (!user?.email) return;

    try {
      setLoadingNotifications(true);
      await api.put('/settings/notifications', {
        email: user.email,
        notifications: nextState,
      });
      toast.success('Notification settings updated');
    } catch (err) {
      console.error('Failed to update notifications', err);
      toast.error('Failed to update notifications');
    } finally {
      setLoadingNotifications(false);
    }
  };

  const handleToggleEmailOnDestruction = async () => {
    const next = !emailOnDestruction;
    setEmailOnDestruction(next);
    await saveNotifications({
      emailOnDestruction: next,
      suspiciousActivity,
    });
  };

  const handleToggleSuspiciousActivity = async () => {
    const next = !suspiciousActivity;
    setSuspiciousActivity(next);
    await saveNotifications({
      emailOnDestruction,
      suspiciousActivity: next,
    });
  };

  const handleSavePreferences = async () => {
    if (!user?.email) return;

    try {
      await api.put('/settings/preferences', {
        email: user.email,
        avatarColor,
        timezone,
        defaultSettings: {
          collection: defaultCollection,
          showPreview: defaultShowPreview,
          maxClicks: Number(defaultMaxClicks) || 0,
          isOneTime: defaultIsOneTime,
        },
        privacy: {
          showCreatorName,
          enableReferrerTracking,
          allowLinkSuggestions, // NEW
        },
        autoDestructRules: {
          expireAfterDays:
            autoExpireDays === '' ? null : Number(autoExpireDays),
          destroyOnFirstClick: autoDestroyOnFirstClick,
        },
      });
      toast.success('Preferences saved');
    } catch (err) {
      console.error('Failed to save preferences', err);
      toast.error('Failed to save preferences');
    }
  };

  const handleSaveSecurityAdvanced = async () => {
    if (!user?.email) return;

    try {
      setLoadingSecurity(true);
      await api.put('/settings/security-advanced', {
        email: user.email,
        twoFactorEnabled,
        securitySettings: {
          notifyNewDevice,
          notifyFailedAttempt,
        },
      });
      toast.success('Security settings updated');
    } catch (err) {
      console.error('Failed to update security settings', err);
      toast.error('Failed to update security settings');
    } finally {
      setLoadingSecurity(false);
    }
  };

  const handleExportData = async () => {
    if (!user?.email) return;
    try {
      setLoadingExport(true);
      const res = await api.get('/settings/export', {
        params: { email: user.email },
      });

      const blob = new Blob([JSON.stringify(res.data, null, 2)], {
        type: 'application/json',
      });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'vanishlink-export.json';
      a.click();
      URL.revokeObjectURL(url);

      toast.success('Data exported');
    } catch (err) {
      console.error('Failed to export data', err);
      toast.error('Failed to export data');
    } finally {
      setLoadingExport(false);
    }
  };

  const handleResetData = async () => {
    if (!user?.email) return;
    const confirmReset = window.confirm(
      'This will delete all your links and analytics data. Continue?'
    );
    if (!confirmReset) return;

    try {
      setLoadingResetData(true);
      await api.post('/settings/reset-data', {
        email: user.email,
      });
      toast.success('All your data was reset');
    } catch (err) {
      console.error('Failed to reset data', err);
      toast.error('Failed to reset data');
    } finally {
      setLoadingResetData(false);
    }
  };

  const handleDeleteAccount = async () => {
    if (!user?.email) return;
    const confirmDelete = window.prompt(
      'Type DELETE to permanently remove your account and all data.'
    );
    if (confirmDelete !== 'DELETE') return;

    try {
      setLoadingDeleteAccount(true);
      await api.delete('/settings/delete-account', {
        data: { email: user.email },
      });
      toast.success('Account deleted');
      // logout() could go here
    } catch (err) {
      console.error('Failed to delete account', err);
      toast.error('Failed to delete account');
    } finally {
      setLoadingDeleteAccount(false);
    }
  };

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold text-white">Settings</h1>

      {/* Profile */}
      <Card className="p-6 border-slate-800 bg-slate-900">
        <div className="flex items-center gap-4 mb-6">
          <div
            className="w-16 h-16 rounded-full flex items-center justify-center text-slate-950 text-2xl font-bold"
            style={{ backgroundColor: avatarColor }}
          >
            {displayName?.[0] || user?.name?.[0] || user?.email?.[0]}
          </div>
          <div>
            <h3 className="text-white font-medium">
              {displayName || user?.name}
            </h3>
            <p className="text-slate-500 text-sm">{user?.email}</p>
          </div>
        </div>

        <div className="grid gap-4 max-w-xl">
          <Input
            label="Display Name"
            value={displayName}
            onChange={(e) => setDisplayName(e.target.value)}
            icon={<User className="w-4 h-4" />}
          />

          <div className="grid md:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs text-slate-400 mb-1">
                Avatar Color
              </label>
              <div className="flex gap-2">
                {colorOptions.map((color) => (
                  <button
                    key={color}
                    type="button"
                    onClick={() => setAvatarColor(color)}
                    className={`w-8 h-8 rounded-full border-2 ${
                      avatarColor === color
                        ? 'border-emerald-400 scale-110'
                        : 'border-slate-700'
                    }`}
                    style={{ backgroundColor: color }}
                  />
                ))}
              </div>
            </div>

            <div>
              <label className="block text-xs text-slate-400 mb-1 flex items-center gap-1">
                <Globe className="w-3 h-3" /> Timezone
              </label>
              <Input
                placeholder="e.g. Asia/Kolkata"
                value={timezone}
                onChange={(e) => setTimezone(e.target.value)}
              />
            </div>
          </div>

          <Button
            className="w-fit"
            onClick={handleUpdateProfile}
            disabled={loadingProfile}
          >
            {loadingProfile ? 'Saving...' : 'Update Profile'}
          </Button>
        </div>
      </Card>

      <div className="grid md:grid-cols-2 gap-6">
        {/* Security - Password */}
        <Card className="p-6 border-slate-800 bg-slate-900">
          <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
            <Lock className="w-4 h-4 text-emerald-500" /> Security
