              disabled={loadingDeleteAccount}
              className="flex items-center gap-2 text-red-300 border-red-700"
            >
              <Trash2 className="w-4 h-4" />
              {loadingDeleteAccount ? 'Deleting...' : 'Delete Account'}
            </Button>
          </div>
        </div>
      </Card>
    </div>
  );
};

