import React, { useState, useEffect } from 'react';
import { useAuth } from '../../hooks/useAuth';
import api from '../../services/api';
import { Card } from '../../components/ui/Card';
import { Activity, CheckCircle, XCircle, Clock } from 'lucide-react';
import toast from 'react-hot-toast';

const WebhookAudit = () => {
  const { user } = useAuth();
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchWebhooks();
  }, []);

  const fetchWebhooks = async () => {
    try {
      setLoading(true);
      const res = await api.get('/analytics/webhooks');
      setLogs(res.data);
    } catch (err) {
      console.error('Failed to fetch webhooks:', err);
      toast.error('Failed to load webhook audit logs');
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'completed':
        return <CheckCircle className="w-5 h-5 text-emerald-500" />;
      case 'failed':
        return <XCircle className="w-5 h-5 text-red-500" />;
      default:
        return <Clock className="w-5 h-5 text-yellow-500" />;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-white mb-2">Webhook Audit</h1>
          <p className="text-slate-400">View real-time delivery logs for your configured webhooks.</p>
        </div>
        <button
          onClick={fetchWebhooks}
          className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-lg text-sm transition"
        >
          Refresh Logs
        </button>
      </div>

      <Card className="p-0 overflow-hidden">
        {loading ? (
          <div className="p-8 text-center text-slate-400">Loading audit logs...</div>
        ) : logs.length === 0 ? (
          <div className="p-8 text-center text-slate-500">
            <Activity className="w-12 h-12 mx-auto mb-3 opacity-20" />
            <p>No webhook deliveries found.</p>
            <p className="text-xs mt-1">Configure webhooks in your link's advanced settings.</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm whitespace-nowrap">
              <thead className="bg-slate-900/50 text-slate-400 border-b border-slate-800">
                <tr>
                  <th className="px-6 py-3 font-medium">Status</th>
                  <th className="px-6 py-3 font-medium">Link</th>
                  <th className="px-6 py-3 font-medium">Event</th>
                  <th className="px-6 py-3 font-medium">URL</th>
                  <th className="px-6 py-3 font-medium">Attempts</th>
                  <th className="px-6 py-3 font-medium">Last Attempt</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-800/50">
                {logs.map((log) => (
                  <tr key={log._id} className="hover:bg-slate-800/20 transition">
                    <td className="px-6 py-4 flex items-center gap-2">
                      {getStatusIcon(log.status)}
                      <span className="capitalize text-slate-300">{log.status}</span>
                    </td>
                    <td className="px-6 py-4 text-emerald-400">
                      /{log.linkId?.slug || 'deleted'}
                    </td>
                    <td className="px-6 py-4 text-slate-300">
                      <span className="px-2 py-1 rounded bg-slate-800 text-xs">{log.event}</span>
                    </td>
                    <td className="px-6 py-4 text-slate-400 truncate max-w-[200px]" title={log.url}>
                      {log.url}
                    </td>
                    <td className="px-6 py-4 text-slate-300">
                      {log.attempts} / {log.maxRetries || 3}
                    </td>
                    <td className="px-6 py-4 text-slate-500">
                      {new Date(log.updatedAt || log.createdAt).toLocaleString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </Card>
    </div>
  );
};

export default WebhookAudit;

